"""Eval report generator — metrics.json → markdown.

Reads the single-source ``results/metrics.json`` (FM-05/12) and produces
a human-readable benchmark report with the headline lift, system comparison
table, per-domain breakdown, and methodology note.
"""

from __future__ import annotations

import json
import logging
import subprocess
from pathlib import Path
from typing import Any

logger = logging.getLogger(__name__)

_HEADER = """# FRB Benchmark Report

> Generated by FinRoot evaluation harness.
"""

_FOOTER = """
---

*Report auto-generated by `finroot.evaluation.report`. Do not edit manually.*
"""


def _fail_loud_missing(path: str) -> None:
    raise FileNotFoundError(
        f"metrics file not found at {path!r}. "
        "Run `scripts/run_evals.py` first to generate it."
    )


def _load_metrics(metrics_path: str) -> dict[str, Any]:
    p = Path(metrics_path)
    if not p.exists():
        _fail_loud_missing(metrics_path)
    return json.loads(p.read_text())


def _git_short_sha() -> str:
    try:
        return subprocess.check_output(["git", "rev-parse", "--short", "HEAD"], text=True).strip()
    except Exception:
        return "unknown"


def _format_pct(v: float) -> str:
    return f"{v * 100:.1f}%"


def _build_headline(data: dict[str, Any]) -> str:
    lift = data.get("composite_lift_vs_rag_pct", 0.0)
    lift_x = data.get("composite_lift_vs_rag_x", 0.0)
    finroot_mean = data.get("headline_finroot_mean", 0.0)
    rag_mean = data.get("headline_rag_mean", 0.0)
    lines = [
        "## Headline Result",
        "",
        f"- **Composite lift vs RAG:** {lift:.1f}% ({lift_x:.2f}×)",
        f"- **FinRoot mean score:** {_format_pct(finroot_mean)}",
        f"- **RAG mean score:** {_format_pct(rag_mean)}",
        "",
    ]
    return "\n".join(lines)


def _build_system_table(data: dict[str, Any]) -> str:
    systems = data.get("systems", {})
    if not systems:
        return "## System Comparison\n\n*No system results available.*\n"
    rows = ["## System Comparison", "", "| System | pass@1 | pass@k | pass^k | Mean Score | n_tasks |", "|-------|--------|--------|--------|------------|---------|"]
    for sys_name, sys_data in systems.items():
        p1 = _format_pct(sys_data.get("pass_at_1", 0.0))
        pk = _format_pct(sys_data.get("pass_at_k", 0.0))
        phk = _format_pct(sys_data.get("pass_hat_k", 0.0))
        mean = f"{sys_data.get('mean_score', 0.0):.4f}"
        nt = str(sys_data.get("n_tasks", 0))
        rows.append(f"| {sys_name} | {p1} | {pk} | {phk} | {mean} | {nt} |")
    rows.append("")
    return "\n".join(rows)


def _build_domain_table(data: dict[str, Any]) -> str:
    systems = data.get("systems", {})
    all_domains: list[str] = []
    for sys_data in systems.values():
        all_domains.extend(sys_data.get("per_domain", {}).keys())
    all_domains = sorted(set(all_domains))
    if not all_domains:
        return "## Per-Domain Breakdown\n\n*No domain data available.*\n"
    header = "| Domain | " + " | ".join(s for s in systems) + " |"
    sep = "|--------|" + "|".join("--------" for _ in systems) + "|"
    rows = ["## Per-Domain Breakdown", "", header, sep]
    for domain in all_domains:
        cells = [domain]
        for sys_data in systems.values():
            score = sys_data.get("per_domain", {}).get(domain, None)
            if score is not None:
                cells.append(_format_pct(score))
            else:
                cells.append("—")
        rows.append("| " + " | ".join(cells) + " |")
    rows.append("")
    return "\n".join(rows)


def _build_methodology_note(data: dict[str, Any]) -> str:
    k = data.get("k", "?")
    n_tasks = data.get("n_tasks", "?")
    mock = data.get("mock", True)
    sha = data.get("as_of_sha", "unknown")
    generated = data.get("generated_at", "unknown")
    lines = [
        "## Methodology",
        "",
        f"- **k (trials per task):** {k}",
        f"- **Number of tasks:** {n_tasks}",
        f"- **Mock mode:** {mock}",
        f"- **Generated at:** {generated}",
        f"- **as_of_sha:** `{sha}`",
        "",
    ]
    return "\n".join(lines)


def generate_report(metrics_path: str = "results/metrics.json") -> str:
    """Read ``metrics.json`` and return a complete markdown report string.

    Args:
        metrics_path: Path to the metrics JSON file.

    Returns:
        Markdown-formatted benchmark report.

    Raises:
        FileNotFoundError: If the metrics file does not exist.
    """
    data = _load_metrics(metrics_path)
    parts = [
        _HEADER,
        _build_headline(data),
        _build_system_table(data),
        _build_domain_table(data),
        _build_methodology_note(data),
        _FOOTER,
    ]
    return "\n".join(parts)


def write_report(metrics_path: str = "results/metrics.json", out_dir: str = "evals/reports") -> Path:
    """Generate the report and write it to disk.

    Writes two files:
        - ``evals/reports/frb_report_<sha>.md`` (versioned)
        - ``evals/reports/latest.md`` (stable link)

    Args:
        metrics_path: Path to the metrics JSON file.
        out_dir: Output directory for reports.

    Returns:
        Path to the versioned report file.
    """
    data = _load_metrics(metrics_path)
    sha = data.get("as_of_sha", _git_short_sha())
    markdown = generate_report(metrics_path)

    out = Path(out_dir)
    out.mkdir(parents=True, exist_ok=True)

    versioned = out / f"frb_report_{sha}.md"
    versioned.write_text(markdown)

    latest = out / "latest.md"
    latest.write_text(markdown)

    logger.info("Wrote report to %s and %s", versioned, latest)
    return versioned
